import xml.etree.ElementTree as ET
from html import unescape

def extract_text(elem):
    """Extract text from element and its children, preserving some tags"""
    if elem is None:
        return ""
    text_parts = []
    if elem.text:
        text_parts.append(elem.text.strip())
    for child in elem:
        if child.tag == 'see':
            cref = child.get('cref', '')
            # Extract just the class name
            if '.' in cref:
                cref = cref.split('.')[-1]
            text_parts.append(cref)
        elif child.tag == 'seealso':
            continue
        elif child.tag == 'param':
            name = child.get('name', '')
            if name:
                param_text = extract_text(child).strip()
                text_parts.append(f"\n  {name}: {param_text}")
        elif child.tag in ['summary', 'remarks', 'returns', 'value']:
            text_parts.append(extract_text(child))
        if child.tail:
            text_parts.append(child.tail.strip())
    return " ".join(filter(None, text_parts))

tree = ET.parse('/home/runner/.nuget/packages/microsoft.agents.ai/1.6.2/lib/net9.0/Microsoft.Agents.AI.xml')
root = tree.getroot()

