    'M:Microsoft.Agents.AI.ChatClientAgent.#ctor',
    'M:Microsoft.Agents.AI.ChatClientAgent.RunAsync',
    'P:Microsoft.Agents.AI.ChatClientAgent.ChatOptions',
]

for member in root.findall(".//member"):
    name = member.get('name', '')
    for key in key_members:
        if key in name:
            summary = member.find('summary')
            print(f"\n{'='*80}")
            print(f"{name}")
            print(f"{'='*80}")
            if summary is not None:
                text = extract_text(summary)
                print(f"Summary: {text[:500]}")

            # Extract params
            params = member.findall('param')
            if params:
                print("\nParameters:")
                for param in params[:5]:
                    pname = param.get('name')
                    ptext = extract_text(param)[:200]
                    print(f"  - {pname}: {ptext}")
