namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability using the Wikipedia API as a free, no-key search source.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
        _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    [Description("Searches the web for information on a query. Returns a list of relevant results with titles and summaries.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit={maxResults}&format=json&utf8=1";

            var response = await _httpClient.GetFromJsonAsync<WikiSearchResponse>(url);
            if (response?.Query?.Search is null or { Count: 0 })
            {
                return $"No results found for '{query}'.";
            }

            var results = response.Query.Search.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    {StripHtml(r.Snippet)}");

            return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

