    public async Task<string> FetchArticleAsync(
        [Description("The exact title of the Wikipedia article to fetch")] string title)
    {
        try
        {
            var encoded = Uri.EscapeDataString(title);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&titles={encoded}&prop=extracts&exintro=0&explaintext=1&exsectionformat=plain&format=json&utf8=1";

            var json = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var pages = doc.RootElement.GetProperty("query").GetProperty("pages");

            foreach (var page in pages.EnumerateObject())
            {
                if (page.Value.TryGetProperty("extract", out var extract))
                {
                    var text = extract.GetString() ?? "";
                    // Truncate to avoid context overflow
                    if (text.Length > 3000)
                    {
                        text = text[..3000] + "\n\n[... truncated for brevity]";
                    }
                    return $"Article: {title}\n\n{text}";
                }
            }

            return $"No article found with title '{title}'.";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch article: {ex.Message}";
        }
    }

