using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can record findings during research.
/// Notes persist in memory for the duration of the session.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short label for the note (e.g., 'History', 'Key People', 'Statistics')")] string topic,
        [Description("The content of the note — facts, quotes, or observations worth remembering")] string content)
    {
        _notes.Add(new Note(topic, content, DateTime.UtcNow));
        return $"Note saved under '{topic}'. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all saved research notes. Use this before writing a summary to review what you've collected.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var formatted = _notes.Select((n, i) =>
            $"[{i + 1}] Topic: {n.Topic}\n    {n.Content}");

        return $"All research notes ({_notes.Count} total):\n\n{string.Join("\n\n", formatted)}";
    }

    [Description("Retrieves notes filtered by topic label (case-insensitive partial match).")]
    public string GetNotesByTopic(
        [Description("The topic label to filter by")] string topic)
    {
        var matches = _notes
            .Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
        {
            return $"No notes found matching topic '{topic}'.";
        }

        var formatted = matches.Select((n, i) =>
            $"[{i + 1}] Topic: {n.Topic}\n    {n.Content}");

        return $"Notes matching '{topic}' ({matches.Count} found):\n\n{string.Join("\n\n", formatted)}";
    }

    private sealed record Note(string Topic, string Content, DateTime SavedAt);
}

