using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability using the Wikipedia API as a free, no-key search source.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
        _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    [Description("Searches the web for information on a query. Returns a list of relevant results with titles and summaries.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit={maxResults}&format=json&utf8=1";

            var response = await _httpClient.GetFromJsonAsync<WikiSearchResponse>(url);
            if (response?.Query?.Search is null or { Count: 0 })
            {
                return $"No results found for '{query}'.";
            }

            var results = response.Query.Search.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    {StripHtml(r.Snippet)}");

            return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetches the full content of a Wikipedia article by its exact title. Use after searching to get detailed information.")]
    public async Task<string> FetchArticleAsync(
        [Description("The exact title of the Wikipedia article to fetch")] string title)
    {
        try
        {
            var encoded = Uri.EscapeDataString(title);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&titles={encoded}&prop=extracts&exintro=0&explaintext=1&exsectionformat=plain&format=json&utf8=1";

            var json = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var pages = doc.RootElement.GetProperty("query").GetProperty("pages");

            foreach (var page in pages.EnumerateObject())
            {
                if (page.Value.TryGetProperty("extract", out var extract))
                {
                    var text = extract.GetString() ?? "";
                    // Truncate to avoid context overflow
                    if (text.Length > 3000)
                    {
                        text = text[..3000] + "\n\n[... truncated for brevity]";
                    }
                    return $"Article: {title}\n\n{text}";
                }
            }

            return $"No article found with title '{title}'.";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch article: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        return System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", "");
    }
}

