using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tool instances ----------------------------------------------------------

var webSearch = new WebSearchTool(new HttpClient());
var notes = new NoteTool();

// --- Build tools from annotated methods -------------------------------------

var tools = new List<AITool>();
tools.AddRange(AIFunctionFactory.Create(webSearch.SearchWebAsync));
tools.AddRange(AIFunctionFactory.Create(webSearch.FetchArticleAsync));
tools.AddRange(AIFunctionFactory.Create(notes.SaveNote));
tools.AddRange(AIFunctionFactory.Create(notes.GetAllNotes));
tools.AddRange(AIFunctionFactory.Create(notes.GetNotesByTopic));

// --- Build agent -------------------------------------------------------------

IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes, then produces a summary.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Run the research loop ---------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║          AI Research Agent                   ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit. The agent will search Wikipedia,      ║");
Console.WriteLine("║  take notes, and produce a summary.          ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    var prompt = $"""
        Research the following topic thoroughly: "{topic}"

        Follow these steps:
        1. Search the web for information about this topic.
        2. Fetch full articles for the most relevant results to get detailed information.
        3. Save important findings as notes using the note-taking tool, organized by sub-topic.
        4. After gathering enough information, review all your notes.
        5. Write a comprehensive summary of your research findings, structured with clear sections.

        Be thorough but concise. Cite the sources you used.
        """;

    Console.WriteLine($"\nResearching '{topic}'...\n");

    try
    {
        var session = await agent.CreateSessionAsync(CancellationToken.None);
        var response = await agent.RunAsync(
            message: prompt,
            session: session,
            options: new ChatClientAgentRunOptions { MaximumIterations = 15 },
            cancellationToken: CancellationToken.None);

        foreach (var message in response.Messages)
        {
            if (message.Role == ChatRole.Assistant)
            {
                foreach (var content in message.Contents)
                {
                    if (content is TextContent text && !string.IsNullOrWhiteSpace(text.Text))
                    {
                        Console.WriteLine(text.Text);
                    }
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.WriteLine("\n" + new string('─', 60) + "\n");
